"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Check, X, FileText, AlertTriangle, Activity, Server, Database, Wifi } from "lucide-react";
import { ngoVerificationQueue, type NgoRow } from "@/lib/mockData";
import { toast } from "sonner";

const fadeUp: any = {
  hidden: { opacity: 0, y: 20 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: { delay: i * 0.1, duration: 0.4 },
  }),
};

const activityLog = [
  { text: "Report #PAW-2024-0848 submitted by citizen Priya S.", time: "Just now", type: "report" },
  { text: "NGO Friendicoes SECA verified by admin", time: "5 min ago", type: "verify" },
  { text: "Bruno (PAW-DOG-0291) vaccination completed", time: "12 min ago", type: "medical" },
  { text: "Citizen Amit K. submitted adoption application for Coco", time: "30 min ago", type: "adopt" },
  { text: "Driver Ravi Kumar completed shift — 4 rescues", time: "1 hr ago", type: "fleet" },
  { text: "System backup completed successfully", time: "2 hr ago", type: "system" },
];

const typeColors: Record<string, string> = {
  report: "#E47F42",
  verify: "#4FC97E",
  medical: "#3B9EFF",
  adopt: "#FFE00F",
  fleet: "#E47F42",
  system: "#BBBBCC",
};

interface StatsData {
  totalRescues: number;
  activeNgos: number;
  pendingVerifications: number;
  animalsInShelters: number;
}

export default function AdminPanel() {
  const [rows, setRows] = useState<(NgoRow & { verified?: boolean })[]>(
    ngoVerificationQueue.map((r) => ({ ...r, verified: false }))
  );
  const [stats, setStats] = useState<StatsData | null>(null);

  // Fetch stats from API
  useEffect(() => {
    fetch("/api/stats")
      .then((r) => r.json())
      .then((data) => setStats(data))
      .catch(() => setStats({ totalRescues: 847, activeNgos: 34, pendingVerifications: 6, animalsInShelters: 312 }));
  }, []);

  const adminStats = stats
    ? [
        { label: "Total Rescues This Month", value: String(stats.totalRescues), icon: "🐾", color: "#E47F42" },
        { label: "Active NGOs", value: String(stats.activeNgos), icon: "🏥", color: "#4FC97E" },
        { label: "Pending NGO Verifications", value: String(stats.pendingVerifications), icon: "⏳", color: "#FFE00F", badge: stats.pendingVerifications > 0 },
        { label: "Animals in Shelters", value: String(stats.animalsInShelters), icon: "🏠", color: "#3B9EFF" },
      ]
    : [];

  const handleApprove = async (id: number) => {
    try {
      await fetch("/api/ngo/verify", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ngoId: id, action: "approve" }),
      });
    } catch { /* ignore */ }

    setRows((prev) =>
      prev.map((r) => (r.id === id ? { ...r, verified: true, status: "Verified" } : r))
    );
    toast.success("NGO verified successfully!", {
      description: "Verification email sent to the organization",
    });
  };

  const handleRequestDocs = () => {
    toast("Document request sent", {
      description: "Email sent to CARE India requesting PAN document",
    });
  };

  return (
    <div className="min-h-screen bg-paw-bg px-4 py-12">
      <div className="mx-auto max-w-6xl">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
        >
          <h1 className="mb-2 text-3xl font-bold sm:text-4xl">
            Admin <span className="text-paw-orange">Panel</span>
          </h1>
          <p className="mb-10 text-paw-muted">Platform overview and management</p>
        </motion.div>

        {/* Stats row */}
        <motion.div
          className="mb-10 grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-4"
          initial="hidden"
          animate="visible"
        >
          {adminStats.map((stat, i) => (
            <motion.div
              key={stat.label}
              custom={i}
              variants={fadeUp}
              className="rounded-xl border border-paw-orange/15 bg-paw-card p-6 transition-all hover:border-paw-orange/30"
              style={{ borderLeftColor: stat.color, borderLeftWidth: "3px" }}
            >
              <div className="flex items-center justify-between mb-3">
                <span className="text-2xl">{stat.icon}</span>
                {stat.badge && (
                  <span className="rounded-full bg-paw-orange/15 px-2.5 py-0.5 text-xs font-bold text-paw-orange">
                    Action needed
                  </span>
                )}
              </div>
              <div className="text-3xl font-bold" style={{ color: stat.color }}>
                {stat.value}
              </div>
              <div className="mt-1 text-sm text-paw-muted">{stat.label}</div>
            </motion.div>
          ))}
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-10">
          {/* Activity Log */}
          <motion.div
            className="lg:col-span-2 rounded-xl border border-paw-orange/15 bg-paw-card p-5"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <div className="flex items-center gap-2 mb-4">
              <Activity className="h-4 w-4 text-paw-orange" />
              <h3 className="text-sm font-semibold">Activity Log</h3>
            </div>
            <div className="space-y-3 max-h-64 overflow-y-auto">
              {activityLog.map((item, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.3 + i * 0.05 }}
                  className="flex items-start gap-3"
                >
                  <div className="mt-1.5 h-2 w-2 rounded-full shrink-0" style={{ backgroundColor: typeColors[item.type] }} />
                  <div className="flex-1">
                    <div className="text-sm text-paw-text">{item.text}</div>
                    <div className="text-xs text-paw-muted">{item.time}</div>
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>

          {/* System Health */}
          <motion.div
            className="rounded-xl border border-paw-green/20 bg-paw-card p-5"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
          >
            <div className="flex items-center gap-2 mb-4">
              <Server className="h-4 w-4 text-paw-green" />
              <h3 className="text-sm font-semibold">System Health</h3>
            </div>
            <div className="space-y-4">
              {[
                { label: "Platform Uptime", value: "99.97%", icon: Wifi, color: "#4FC97E" },
                { label: "API Calls Today", value: "14,832", icon: Activity, color: "#3B9EFF" },
                { label: "Storage Used", value: "42.3 GB", icon: Database, color: "#E47F42" },
              ].map((item) => {
                const Icon = item.icon;
                return (
                  <div key={item.label} className="flex items-center gap-3">
                    <div className="rounded-lg p-2" style={{ backgroundColor: `${item.color}15` }}>
                      <Icon className="h-4 w-4" style={{ color: item.color }} />
                    </div>
                    <div className="flex-1">
                      <div className="text-xs text-paw-muted">{item.label}</div>
                      <div className="text-sm font-bold" style={{ color: item.color }}>{item.value}</div>
                    </div>
                    <div className="h-2 w-2 rounded-full bg-paw-green" title="Healthy" />
                  </div>
                );
              })}
              <div className="text-xs text-paw-green mt-2 pt-2 border-t border-paw-green/10">
                ✓ All systems operational
              </div>
            </div>
          </motion.div>
        </div>

        {/* NGO Verification Queue */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
        >
          <h2 className="mb-4 text-xl font-bold">NGO Verification Queue</h2>
          <div className="overflow-x-auto rounded-xl border border-paw-orange/15 bg-paw-card">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-paw-orange/10">
                  <th className="px-5 py-4 text-left font-medium text-paw-muted">NGO Name</th>
                  <th className="px-5 py-4 text-left font-medium text-paw-muted">City</th>
                  <th className="px-5 py-4 text-left font-medium text-paw-muted hidden sm:table-cell">Applied On</th>
                  <th className="px-5 py-4 text-left font-medium text-paw-muted hidden md:table-cell">Documents</th>
                  <th className="px-5 py-4 text-left font-medium text-paw-muted">Status</th>
                  <th className="px-5 py-4 text-right font-medium text-paw-muted">Action</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((row) => (
                  <tr
                    key={row.id}
                    className={`border-b border-paw-orange/5 transition-colors ${
                      row.verified ? "bg-paw-green/5" : "hover:bg-white/[0.02]"
                    }`}
                  >
                    <td className="px-5 py-4 font-medium">{row.name}</td>
                    <td className="px-5 py-4 text-paw-muted">{row.city}</td>
                    <td className="px-5 py-4 text-paw-muted hidden sm:table-cell">{row.appliedOn}</td>
                    <td className="px-5 py-4 hidden md:table-cell">
                      <span className={`flex items-center gap-1.5 text-sm ${row.documentsOk ? "text-paw-green" : "text-paw-gold"}`}>
                        {row.documentsOk ? <Check className="h-4 w-4" /> : <AlertTriangle className="h-4 w-4" />}
                        {row.documents}
                      </span>
                    </td>
                    <td className="px-5 py-4">
                      {row.verified ? (
                        <span className="inline-flex items-center gap-1 rounded-full bg-paw-green/15 px-2.5 py-0.5 text-xs font-bold text-paw-green">
                          <Check className="h-3 w-3" /> Verified
                        </span>
                      ) : (
                        <span
                          className={`rounded-full px-2.5 py-0.5 text-xs font-medium ${
                            row.status === "Pending"
                              ? "text-paw-gold bg-paw-gold/10"
                              : "text-paw-orange bg-paw-orange/10"
                          }`}
                        >
                          {row.status}
                        </span>
                      )}
                    </td>
                    <td className="px-5 py-4 text-right">
                      {row.verified ? (
                        <span className="text-xs text-paw-green">Done</span>
                      ) : row.documentsOk ? (
                        <div className="flex items-center justify-end gap-2">
                          <button
                            onClick={() => handleApprove(row.id)}
                            className="rounded-lg bg-paw-green/15 px-3 py-1.5 text-xs font-medium text-paw-green transition-all hover:bg-paw-green/25"
                          >
                            Approve
                          </button>
                          <button className="rounded-lg border border-paw-red/30 px-3 py-1.5 text-xs font-medium text-paw-red transition-all hover:bg-paw-red/10">
                            Reject
                          </button>
                        </div>
                      ) : (
                        <button
                          onClick={handleRequestDocs}
                          className="rounded-lg bg-paw-orange/15 px-3 py-1.5 text-xs font-medium text-paw-orange transition-all hover:bg-paw-orange/25"
                        >
                          <FileText className="mr-1 inline h-3 w-3" />
                          Request Docs
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  LayoutDashboard,
  Bell,
  Truck,
  PawPrint,
  BarChart3,
  Check,
  X,
  Activity,
  Clock,
  Zap,
  Wrench,
} from "lucide-react";
import { alertCards, rescuesPerDay, speciesDistribution, responseTimeTrend } from "@/lib/mockData";
import { toast } from "sonner";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  LineChart,
  Line,
} from "recharts";
import Link from "next/link";

const sidebarLinks = [
  { label: "Overview", icon: LayoutDashboard },
  { label: "Incoming Alerts", icon: Bell },
  { label: "My Fleet", icon: Truck },
  { label: "Animal Profiles", icon: PawPrint },
  { label: "Analytics", icon: BarChart3 },
];

const fadeUp: any = {
  hidden: { opacity: 0, y: 20 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: { delay: i * 0.08, duration: 0.4 },
  }),
};

// ---- Overview Tab ----
function OverviewTab() {
  const overviewStats = [
    { label: "Total Alerts Today", value: "23", icon: Bell, color: "#E47F42" },
    { label: "Accepted Today", value: "18", icon: Check, color: "#4FC97E" },
    { label: "Avg Response Time", value: "44 min", icon: Clock, color: "#3B9EFF" },
    { label: "Fleet Utilization", value: "78%", icon: Zap, color: "#FFE00F" },
  ];

  const recentActivity = [
    { text: "Van MH-04-AB-1234 picked up dog at Lajpat Nagar", time: "2 min ago", color: "#4FC97E" },
    { text: "New critical report: Cow at Karol Bagh (severity 8/10)", time: "5 min ago", color: "#FF4F4F" },
    { text: "Bruno (PAW-DOG-0291) vaccination completed", time: "12 min ago", color: "#3B9EFF" },
    { text: "Driver Ravi Kumar completed shift — 4 rescues", time: "25 min ago", color: "#E47F42" },
    { text: "Friendicoes SECA shelter at 92% capacity", time: "1 hr ago", color: "#FFE00F" },
  ];

  return (
    <motion.div className="space-y-6" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <h2 className="text-xl font-bold">Overview</h2>

      {/* Stats grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {overviewStats.map((stat, i) => {
          const Icon = stat.icon;
          return (
            <motion.div
              key={stat.label}
              custom={i}
              variants={fadeUp}
              initial="hidden"
              animate="visible"
              className="rounded-xl border border-paw-orange/15 bg-paw-card p-4"
              style={{ borderLeftColor: stat.color, borderLeftWidth: "3px" }}
            >
              <Icon className="h-5 w-5 mb-2" style={{ color: stat.color }} />
              <div className="text-2xl font-bold" style={{ color: stat.color }}>{stat.value}</div>
              <div className="text-xs text-paw-muted mt-1">{stat.label}</div>
            </motion.div>
          );
        })}
      </div>

      {/* Activity feed */}
      <div className="rounded-xl border border-paw-orange/15 bg-paw-card p-5">
        <div className="flex items-center gap-2 mb-4">
          <Activity className="h-4 w-4 text-paw-orange" />
          <h3 className="text-sm font-medium">Recent Activity</h3>
        </div>
        <div className="space-y-3">
          {recentActivity.map((item, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: i * 0.05 }}
              className="flex items-start gap-3"
            >
              <div className="mt-1.5 h-2 w-2 rounded-full shrink-0" style={{ backgroundColor: item.color }} />
              <div className="flex-1 min-w-0">
                <div className="text-sm text-paw-text">{item.text}</div>
                <div className="text-xs text-paw-muted">{item.time}</div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

// ---- Incoming Alerts Tab ----
function IncomingAlerts() {
  const [cards, setCards] = useState(
    alertCards.map((c) => ({ ...c, accepted: false }))
  );

  const handleAccept = (id: number) => {
    setCards((prev) =>
      prev.map((c) => (c.id === id ? { ...c, accepted: true } : c))
    );
    toast.success("Van MH-04-AB-1234 assigned. Driver notified.", {
      description: "Dispatching rescue van to location",
    });
  };

  return (
    <motion.div className="space-y-4" initial="hidden" animate="visible">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Incoming Alerts</h2>
        <span className="rounded-full bg-paw-red/15 px-3 py-1 text-xs font-bold text-paw-red">
          {cards.filter((c) => !c.accepted).length} pending
        </span>
      </div>
      {cards.map((card, i) => (
        <motion.div
          key={card.id}
          custom={i}
          variants={fadeUp}
          initial="hidden"
          animate="visible"
          className={`relative flex items-stretch overflow-hidden rounded-xl border transition-all duration-500 ${
            card.accepted
              ? "border-paw-green/40 bg-paw-green/5"
              : "border-paw-orange/15 bg-paw-card hover:border-paw-orange/30"
          }`}
        >
          <div className="w-1.5 shrink-0" style={{ backgroundColor: card.accepted ? "#4FC97E" : card.color }} />
          <div className="flex flex-1 flex-col sm:flex-row items-start sm:items-center gap-4 p-5">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-3 mb-2">
                <span className="text-2xl">{card.animalIcon}</span>
                <span className="font-semibold text-lg">{card.animal}</span>
                <span
                  className="rounded-full px-2.5 py-0.5 text-xs font-bold"
                  style={{
                    backgroundColor: card.accepted ? "rgba(79,201,126,0.15)" : `${card.color}20`,
                    color: card.accepted ? "#4FC97E" : card.color,
                  }}
                >
                  {card.accepted ? "✓ DISPATCHING" : `${card.severity}/10 ${card.severityLabel}`}
                </span>
              </div>
              <div className="text-sm text-paw-muted">📍 {card.location} · {card.reportedAgo}</div>
            </div>
            {!card.accepted ? (
              <div className="flex gap-2 shrink-0">
                <button
                  onClick={() => handleAccept(card.id)}
                  className="flex items-center gap-1.5 rounded-lg bg-paw-green/15 px-4 py-2 text-sm font-medium text-paw-green transition-all hover:bg-paw-green/25"
                >
                  <Check className="h-4 w-4" /> Accept
                </button>
                <button className="flex items-center gap-1.5 rounded-lg border border-paw-red/30 px-4 py-2 text-sm font-medium text-paw-red transition-all hover:bg-paw-red/10">
                  <X className="h-4 w-4" /> Reject
                </button>
              </div>
            ) : (
              <motion.div
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                className="flex items-center gap-2 rounded-lg bg-paw-green/15 px-4 py-2 text-sm font-medium text-paw-green"
              >
                <Check className="h-4 w-4" /> Dispatching van...
              </motion.div>
            )}
          </div>
        </motion.div>
      ))}
    </motion.div>
  );
}

// ---- My Fleet Tab ----
function FleetTab() {
  const fleet = [
    { id: "MH-04-AB-1234", driver: "Ravi Kumar", status: "dispatched", mission: "PAW-2024-0844", rating: 4.8 },
    { id: "DL-01-CD-5678", driver: "Suresh Patel", status: "available", mission: null, rating: 4.6 },
    { id: "DL-08-EF-9012", driver: "Amit Singh", status: "maintenance", mission: null, rating: 4.9 },
  ];

  const statusColors: Record<string, { bg: string; text: string; label: string }> = {
    dispatched: { bg: "bg-paw-orange/15", text: "text-paw-orange", label: "On Mission" },
    available: { bg: "bg-paw-green/15", text: "text-paw-green", label: "Available" },
    maintenance: { bg: "bg-paw-muted/15", text: "text-paw-muted", label: "Maintenance" },
  };

  return (
    <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <h2 className="text-xl font-bold">My Fleet</h2>
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {fleet.map((v, i) => {
          const sc = statusColors[v.status];
          return (
            <motion.div
              key={v.id}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              className="rounded-xl border border-paw-orange/15 bg-paw-card p-5 space-y-3"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Truck className="h-5 w-5 text-paw-orange" />
                  <span className="font-mono font-medium">{v.id}</span>
                </div>
                <span className={`rounded-full px-2.5 py-0.5 text-xs font-bold ${sc.bg} ${sc.text}`}>{sc.label}</span>
              </div>
              <div className="text-sm">
                <div className="text-paw-text font-medium">{v.driver}</div>
                <div className="text-paw-muted text-xs">⭐ {v.rating} rating</div>
              </div>
              {v.mission && (
                <div className="text-xs text-paw-orange">Active: #{v.mission}</div>
              )}
              {v.status === "maintenance" && (
                <div className="flex items-center gap-1.5 text-xs text-paw-muted">
                  <Wrench className="h-3 w-3" /> Scheduled service — back tomorrow
                </div>
              )}
            </motion.div>
          );
        })}
      </div>
    </motion.div>
  );
}

// ---- Animal Profiles Tab ----
function AnimalProfilesTab() {
  const animals = [
    { id: "PAW-DOG-0291", name: "Bruno", species: "Dog", status: "UNDER TREATMENT", color: "#3B9EFF", emoji: "🐕" },
    { id: "PAW-DOG-0285", name: "Coco", species: "Dog", status: "AVAILABLE FOR ADOPTION", color: "#4FC97E", emoji: "🐕" },
    { id: "PAW-CAT-0102", name: "Whiskers", species: "Cat", status: "RECOVERING", color: "#FFE00F", emoji: "🐈" },
    { id: "PAW-COW-0058", name: "Ganga", species: "Cow", status: "UNDER TREATMENT", color: "#3B9EFF", emoji: "🐄" },
    { id: "PAW-BRD-0034", name: "Chirpy", species: "Bird", status: "AVAILABLE FOR ADOPTION", color: "#4FC97E", emoji: "🐦" },
  ];

  return (
    <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <h2 className="text-xl font-bold">Animal Profiles</h2>
      <div className="overflow-x-auto rounded-xl border border-paw-orange/15 bg-paw-card">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-paw-orange/10">
              <th className="px-5 py-3 text-left font-medium text-paw-muted">Animal</th>
              <th className="px-5 py-3 text-left font-medium text-paw-muted">ID</th>
              <th className="px-5 py-3 text-left font-medium text-paw-muted hidden sm:table-cell">Species</th>
              <th className="px-5 py-3 text-left font-medium text-paw-muted">Status</th>
              <th className="px-5 py-3 text-right font-medium text-paw-muted">Action</th>
            </tr>
          </thead>
          <tbody>
            {animals.map((a) => (
              <tr key={a.id} className="border-b border-paw-orange/5 hover:bg-white/[0.02]">
                <td className="px-5 py-3">
                  <div className="flex items-center gap-2">
                    <span className="text-xl">{a.emoji}</span>
                    <span className="font-medium">{a.name}</span>
